func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Extract host from URL (remove port if present)
	host, _, err := net.SplitHostPort(parsedURL.Host)
	if err != nil {
		// No port specified, use full host
		host = parsedURL.Host
	}

	// Resolve host to IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to resolve webhook URL host",
		})
	}

	// Validate all IP addresses are public and non-reserved (prevents SSRF)
	for _, ip := range ips {
		if ip.IsLoopback() ||
			ip.IsLinkLocalUnicast() ||
			ip.IsLinkLocalMulticast() ||
			ip.IsInterfaceLocalMulticast() ||
			ip.IsPrivate() ||
			ip.IsMulticast() {
			return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
				"success": false,
				"error":   "Webhook URL cannot resolve to a private or reserved IP address",
			})
		}
	}

	// Select target IP (prefer IPv4 for broader compatibility)
	var targetIP net.IP
	for _, ip := range ips {
		if ip.To4() != nil {
			targetIP = ip
			break
		}
	}
	if targetIP == nil {
		targetIP = ips[0] // Fallback to first available IP (IPv6)
	}

	// Create custom transport to use pre-resolved IP (prevents DNS rebinding attacks)
	dialer := &net.Dialer{
		Timeout: 3 * time.Second,
	}
	transport := &http.Transport{
		DialContext: func(ctx context.Context, network, addr string) (net.Conn, error) {
			// Extract port from original address, use default if missing
			_, port, splitErr := net.SplitHostPort(addr)
			if splitErr != nil {
				port = "80"
				if parsedURL.Scheme == "https" {
					port = "443"
				}
			}
			targetAddr := net.JoinHostPort(targetIP.String(), port)
			return dialer.DialContext(ctx, network, targetAddr)
		},
		TLSClientConfig: &tls.Config{
