	// - Custom transport to use pre-validated IP
	client := &http.Client{
		Transport: transport,
		Timeout:   3 * time.Second,
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}

	// Send GET test request to webhook URL (as per requirement)
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		// Return generic error to avoid leaking internal server details
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to send test request to webhook URL. Please ensure the URL is publicly reachable.",
		})
	}
	defer resp.Body.Close()

	// Check if the webhook responded successfully (2xx status)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
