// isRestrictedIP checks if an IP address is in a restricted (non-public) range
func isRestrictedIP(ip net.IP) bool {
	// Check loopback addresses (127.0.0.0/8, ::1/128)
	if ip.IsLoopback() {
		return true
	}
	// Check private networks (RFC 1918 for IPv4, RFC 4193 for IPv6)
	if ip.IsPrivate() {
		return true
	}
	// Check link-local unicast addresses (169.254.0.0/16, fe80::/10)
	if ip.IsLinkLocalUnicast() {
		return true
	}
	// Check link-local multicast addresses (224.0.0.0/24, ff02::/16)
	if ip.IsLinkLocalMulticast() {
		return true
	}
	// Check multicast addresses (224.0.0.0/4, ff00::/8)
	if ip.IsMulticast() {
		return true
	}
	// Check unspecified addresses (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return true
	}
	// Check Carrier Grade NAT range (RFC 6598: 100.64.0.0/10)
	cgnatCIDR := &net.IPNet{
		IP:   net.IPv4(100, 64, 0, 0),
		Mask: net.CIDRMask(10, 32),
	}
	if cgnatCIDR.Contains(ip) {
		return true
	}
	// Check documentation ranges (RFC 5737 for IPv4, RFC 3849 for IPv6)
	docRanges := []*net.IPNet{
		{IP: net.IPv4(192, 0, 2, 0), Mask: net.CIDRMask(24, 32)},
		{IP: net.IPv4(198, 51, 100, 0), Mask: net.CIDRMask(24, 32)},
		{IP: net.IPv4(203, 0, 113, 0), Mask: net.CIDRMask(24, 32)},
		{IP: net.ParseIP("2001:db8::"), Mask: net.CIDRMask(32, 128)},
	}
	for _, dr := range docRanges {
		if dr.Contains(ip) {
			return true
		}
	}
	return false
}
// safeDialContext resolves the host to IPs, validates they are not restricted, and dials the first valid IP
func safeDialContext(ctx context.Context, network, address string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(address)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}
	// Resolve host to IP addresses
	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}
	// Filter out restricted IPs
	var validIPs []net.IP
	for _, ip := range ips {
		if!isRestrictedIP(ip) {
			validIPs = append(validIPs, ip)
		}
	}
	if len(validIPs) == 0 {
		return nil, fmt.Errorf("host resolves to restricted IP addresses")
	}
	// Attempt to dial each valid IP until a connection is established
	var lastErr error
	dialer := net.Dialer{}
	for _, ip := range validIPs {
		dialAddr := net.JoinHostPort(ip.String(), port)
		conn, err := dialer.DialContext(ctx, network, dialAddr)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}
	return nil, fmt.Errorf("failed to connect to any valid IP: %w", lastErr)
}
