import (
	"log"
	"net/http"
	"time"
	"github.com/gofiber/fiber/v2"
)
// savedWebhookURL is in-memory storage for the configured webhook (replace with persistent storage in production)
var savedWebhookURL string
// WebhookConfigRequest defines the expected structure of the incoming POST request body
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfigRequest
	// Parse incoming JSON request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "failed to parse request body: " + err.Error(),
		})
	}
	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is a required field",
		})
	}
	// Create HTTP client with 3-second timeout for test request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	// Send test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook validation failed: " + err.Error(),
		})
	}
	// Ensure response body is closed to prevent resource leaks
	defer resp.Body.Close()
	// Verify the webhook returned a 2xx success status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook validation failed: received non-success status " + resp.Status,
		})
	}
	// Save the validated webhook configuration
	savedWebhookURL = req.WebhookURL
	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "webhook configured successfully",
		"webhook_url": savedWebhookURL,
	})
}
func main() {
	// Initialize Fiber application
	app := fiber.New()
	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)
	// Start server on port 3000, log any startup errors
	log.Fatal(app.Listen(":3000"))
}

