package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhookRequest represents the incoming request payload for webhook configuration
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// savedWebhookURL is in-memory storage for the validated webhook URL
// For production use, replace with persistent storage (e.g. database, config file)
var savedWebhookURL string

// ConfigureWebhook handles POST requests to set up and validate a webhook endpoint
func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req ConfigureWebhookRequest

	// Parse incoming JSON request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook endpoint
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Prevent resource leaks by closing response body

	// Verify webhook returns a successful 2xx status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save the validated webhook configuration
	savedWebhookURL = req.WebhookURL

	// Return success response with configuration details
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": savedWebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

