func isRestrictedIP(ip net.IP) bool {
	// Block unspecified addresses (0.0.0.0, ::)
	if ip.IsUnspecified() {
		return true
	}
	// Block loopback addresses (127.0.0.0/8, ::1/128)
	if ip.IsLoopback() {
