package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global storage for webhook configuration with thread safety
var (
	configuredWebhookURL string
	webhookMutex         sync.RWMutex
)

// ConfigureWebhook handles webhook configuration requests
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Define request body structure
	var req struct {
		WebhookURL string `json:"webhook_url"`
	}

	// Parse incoming JSON request body
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "invalid request body: " + err.Error(),
		})
	}

	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook availability
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed

	// Validate successful response status (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL returned non-success status: " + resp.Status,
		})
	}

	// Save validated webhook configuration (thread-safe write)
	webhookMutex.Lock()
	configuredWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response with configuration details
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "webhook configured successfully",
		"webhook_url": req.WebhookURL,
		"test_status": resp.Status,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("failed to start server: " + err.Error())
	}
}

