// isIPAllowed checks if an IP address is a public, non-internal address
func isIPAllowed(ip net.IP) bool {
	// Block loopback addresses (127.0.0.0/8, ::1/128)
	if ip.IsLoopback() {
		return false
	}
	// Block private network ranges (RFC 1918, RFC 4193)
	if ip.IsPrivate() {
		return false
	}
	// Block link-local unicast addresses (169.254.0.0/16, fe80::/10)
	if ip.IsLinkLocalUnicast() {
		return false
	}
	// Block link-local multicast addresses (224.0.0.0/24, ff02::/16)
	if ip.IsLinkLocalMulticast() {
		return false
	}
	// Allow all other IPs
	return true
}
// getAllowedIPs resolves a hostname and returns only allowed public IP addresses
func getAllowedIPs(host string) ([]net.IP, error) {
	ips, err := net.LookupIP(host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}
	var allowedIPs []net.IP
	for _, ip := range ips {
		if isIPAllowed(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}
	if len(allowedIPs) == 0 {
		return nil, fmt.Errorf("host %s has no public IP addresses", host)
	}
	return allowedIPs, nil
}
// secureDialContext dials a TCP connection only to allowed public IP addresses
func secureDialContext(ctx context.Context, network, address string) (net.Conn, error) {
	dialer := &net.Dialer{
		Timeout:   3 * time.Second,
		KeepAlive: 30 * time.Second,
	}
	// Split address into host and port (address always includes port for HTTP/HTTPS)
	host, port, err := net.SplitHostPort(address)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}
	// Get allowed IPs for the host
	allowedIPs, err := getAllowedIPs(host)
	if err!= nil {
		return nil, err
	}
	// Try dialing each allowed IP until successful
	var firstErr error
	for _, ip := range allowedIPs {
		ipAddr := net.JoinHostPort(ip.String(), port)
		conn, err := dialer.DialContext(ctx, network, ipAddr)
		if err == nil {
			return conn, nil
		}
		if firstErr == nil {
			firstErr = err
		}
	}
	return nil, firstErr
}
