	}
	// Configure TLS with correct ServerName and secure minimum version
	tlsConfig := &tls.Config{
		ServerName: host,
		MinVersion: tls.VersionTLS12,
	}
	// Try dialing each allowed IP until successful
	var firstErr error
	dialer := &net.Dialer{
