	webhookMutex         sync.RWMutex
)
// ConfigureWebhookRequest defines the expected structure of the incoming POST request body
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}
// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid request format: %v", err),
		})
	}
	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}
	// Create HTTP client with 3-second timeout for test request
	client := http.Client{
		Timeout: 3 * time.Second,
	}
	// Send test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent resource leaks
	// Verify test request returned a successful 2xx status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Test request failed with status: %s", resp.Status),
		})
	}
	// Save validated webhook configuration (thread-safe write)
	webhookMutex.Lock()
	configuredWebhookURL = req.WebhookURL
	webhookMutex.Unlock()
	// Read saved configuration for response (thread-safe read)
	webhookMutex.RLock()
	savedURL := configuredWebhookURL
	webhookMutex.RUnlock()
	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": savedURL,
	})
