package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// savedWebhookURL stores the configured webhook URL (in-memory storage for demonstration)
var savedWebhookURL string

// WebhookConfigRequest represents the incoming request body for webhook configuration
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url" validate:"required,url"`
}

// GenericResponse is a standard JSON response structure
type GenericResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
	Data    any    `json:"data,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(GenericResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(GenericResponse{
			Success: false,
			Message: "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3-second timeout as required
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the webhook URL
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(GenericResponse{
			Success: false,
			Message: "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Verify the webhook returns a success status code (2xx range)
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(http.StatusBadRequest).JSON(GenericResponse{
			Success: false,
			Message: "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save the validated webhook configuration
	savedWebhookURL = req.WebhookURL

	// Return success response with configured data
	return ctx.Status(http.StatusOK).JSON(GenericResponse{
		Success: true,
		Message: "Webhook configured successfully",
		Data: map[string]string{
			"webhook_url": savedWebhookURL,
		},
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration POST endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

