package main

import (
	"log"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// Global variables to store webhook configuration with thread safety
var (
	savedWebhookURL string
	mu              sync.RWMutex
)

// WebhookConfigRequest represents the incoming request body for webhook configuration
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// WebhookResponse represents the JSON response structure
type WebhookResponse struct {
	Success    bool   `json:"success"`
	Message    string `json:"message,omitempty"`
	Error      string `json:"error,omitempty"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Invalid request body: " + err.Error(),
		})
	}

	// Validate that webhook_url is provided
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed after processing

	// Verify test request returned a successful 2xx status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Error:   "Webhook test returned non-success status: " + resp.Status,
		})
	}

	// Safely save the valid webhook URL with mutex lock to prevent race conditions
	mu.Lock()
	savedWebhookURL = req.WebhookURL
	mu.Unlock()

	// Return successful response
	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success:    true,
		Message:    "Webhook configured successfully",
		WebhookURL: req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

