// isIPAllowed checks if an IP address is a public, non-reserved address
func isIPAllowed(ip net.IP) bool {
	// Block loopback addresses (127.0.0.0/8, ::1/128)
	if ip.IsLoopback() {
		return false
	}
	// Block private IP ranges (RFC 1918, RFC 4193)
	if ip.IsPrivate() {
		return false
	}
	// Block link-local unicast addresses (169.254.0.0/16, fe80::/10)
	if ip.IsLinkLocalUnicast() {
		return false
	}
	// Block link-local multicast addresses (224.0.0.0/24, ff02::/16)
	if ip.IsLinkLocalMulticast() {
		return false
	}
	// Block CGNAT shared address range (100.64.0.0/10, RFC 6598)
	if ip4 := ip.To4(); ip4 != nil {
		if ip4[0] == 100 && ip4[1] >= 64 && ip4[1] <= 127 {
			return false
		}
	}
	return true
}
// safeDialer is a base dialer with timeout settings
var safeDialer = &net.Dialer{
	Timeout:   5 * time.Second,
	KeepAlive: 5 * time.Second,
	Resolver:  net.DefaultResolver,
}
// customDialContext validates IP addresses before establishing a connection, preventing DNS rebinding
func customDialContext(ctx context.Context, network, address string) (net.Conn, error) {
	// Split address into host and port
	host, port, err := net.SplitHostPort(address)
	if err != nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}
	// Resolve host to IP addresses once to avoid DNS rebinding
	ips, err := net.DefaultResolver.LookupIP(ctx, "ip", host)
	if err != nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}
	// Filter out non-allowed IPs
	var allowedIPs []net.IP
	for _, ip := range ips {
		if isIPAllowed(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}
	if len(allowedIPs) == 0 {
		return nil, fmt.Errorf("host %s resolves to no allowed public IP addresses", host)
	}
	// Attempt to dial each allowed IP until successful or all fail
	var lastErr error
	for _, ip := range allowedIPs {
		// Dial the IP directly to reuse the pre-validated IP (prevents DNS rebinding)
		ipAddress := net.JoinHostPort(ip.String(), port)
		conn, err := safeDialer.DialContext(ctx, network, ipAddress)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}
	// Return the last error if all IPs failed
	return nil, fmt.Errorf("failed to connect to any allowed IP for host %s: %w", host, lastErr)
