import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookConfig stores the validated webhook URL with mutex protection for concurrent access
var (
	webhookConfig = struct {
		sync.RWMutex
		URL string
	}{}
)

// ConfigureWebhookRequest represents the JSON body structure for the webhook configuration request
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the POST request to configure and validate a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body: " + err.Error(),
		})
	}

	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3-second timeout for test request
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to the provided webhook URL
	resp, err := httpClient.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook validation failed: " + err.Error(),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed after processing

	// Verify the webhook returns a 200 OK status
	if resp.StatusCode != http.StatusOK {
		return ctx.Status(fiber.StatusUnprocessableEntity).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook returned non-success status: " + resp.Status,
		})
	}

	// Save the validated webhook URL safely for concurrent access
	webhookConfig.Lock()
	webhookConfig.URL = req.WebhookURL
	webhookConfig.Unlock()

	// Return success response with configuration details
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic("Failed to start server: " + err.Error())
	}
}

