package main

import (
	"fmt"
	"log"
	"net/http"
	"net/url"
	"time"

	"github.com/gofiber/fiber/v2"
)

// ConfigureWebhookRequest defines the structure of the incoming request body
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// appConfig stores the application's configuration (in-memory for demonstration)
var appConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse JSON request body
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("invalid request body: %v", err),
		})
	}

	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format correctness
	if _, err := url.ParseRequestURI(req.WebhookURL); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("invalid webhook URL format: %v", err),
		})
	}

	// Create HTTP client with 3-second timeout as required
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("test request failed: %v", err),
		})
	}
	defer resp.Body.Close()

	// Verify test request returned a successful status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("test request returned non-success status: %s", resp.Status),
		})
	}

	// Save the validated webhook configuration
	appConfig.WebhookURL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": appConfig.WebhookURL,
	})
}

func main() {
	// Initialize Fiber application
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	log.Fatal(app.Listen(":3000"))
}

