import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfigRequest represents the incoming request body for webhook configuration
type WebhookConfigRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// Package-level variables to store the saved webhook configuration (thread-safe)
var (
	savedWebhookURL string
	webhookMutex    sync.RWMutex
)

// ConfigureWebhook handles the webhook configuration POST request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse incoming JSON request body
	var req WebhookConfigRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Invalid request body: %v", err),
		})
	}

	// Validate required webhook_url field
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook_url is a required field",
		})
	}

	// Create HTTP client with 3 second timeout as required
	client := http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to the provided webhook URL
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Webhook validation failed: %v", err),
		})
	}
	defer resp.Body.Close() // Ensure response body is closed to prevent leaks

	// Check if test request returned a successful 2xx status code
	if resp.StatusCode < http.StatusOK || resp.StatusCode >= http.StatusMultipleChoices {
		return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
			"success": false,
			"error":   fmt.Sprintf("Test request returned non-success status: %s", resp.Status),
		})
	}

	// Save the validated webhook URL (thread-safe write)
	webhookMutex.Lock()
	savedWebhookURL = req.WebhookURL
	webhookMutex.Unlock()

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Register the webhook configuration endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional endpoint to verify current saved webhook configuration
	app.Get("/current-webhook", func(ctx *fiber.Ctx) error {
		webhookMutex.RLock()
		defer webhookMutex.RUnlock()
		return ctx.JSON(fiber.Map{
			"current_webhook_url": savedWebhookURL,
		})
	})

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic(fmt.Sprintf("Failed to start server: %v", err))
	}
}

